// ── Helpers ─────────────────────────────────────────────────────────

function mockBettyResult(overrides: {
  b1?: number;
  deficit?: number;
  buleyMeasure?: number;
  voidDimensions?: number;
  landauerHeat?: number;
}) {
  return {
    ast: null,
    output: '',
    b1: overrides.b1 ?? 0,
    diagnostics: [],
    buleyMeasure: overrides.buleyMeasure ?? 0,
    stability: null,
    optimizer: null,
    coarseningSynthesis: null,
    voidDimensions: overrides.voidDimensions ?? 0,
    landauerHeat: overrides.landauerHeat ?? 0,
    deficit: overrides.deficit != null ? { perNode: new Map(), totalDeficit: overrides.deficit, diagnostics: [] } : null,
    semanticCompatibility: null,
    hopeCertificate: null,
    clockwork: { sound: true, reason: '' },
    universe: { admitted: true, reason: '' },
    knotBinary: null,
  };
}

function mockGhostMass(ghostMass = 0) {
  return {
    forked_mass: 0,
    live_mass: 0,
    folded_mass: 0,
    vented_mass: 0,
    accounted_mass: 0,
    ghost_mass: ghostMass,
    leak_debt: 0,
  };
}

function mockFunction(name: string, beta1: number, deficit: number) {
  return {
    functionName: name,
    ggSource: '',
    ast: { nodes: new Map(), edges: [] },
    bettyResult: mockBettyResult({ b1: beta1, deficit }),
    sourceMap: new Map(),
    diagnostics: [],
    ghostMassLedger: mockGhostMass(),
  };
}

function mockFileResult(filePath: string, functions: ReturnType<typeof mockFunction>[]) {
  return {
    filePath,
    result: {
      filePath,
      language: 'typescript',
      structuredDeclarations: [],
      proofDeclarations: [],
      functions,
      errors: [],
    },
  };
}

// ── Tests ───────────────────────────────────────────────────────────

describe('extractFunctionMetrics', () => {
  test('learning function has beta1 > 0', () => {
    const func = mockFunction('handleRequest', 3, 1);
    const metrics = extractFunctionMetrics(func as never, 'src/server.ts');

    expect(metrics.functionName).toBe('handleRequest');
    expect(metrics.beta1).toBe(3);
    expect(metrics.deficit).toBe(1);
    expect(metrics.isLearning).toBe(true);
    // godWeight = R - min(v, R) + 1 = 4 - min(1, 4) + 1 = 4
    expect(metrics.godWeight).toBe(4);
  });

  test('deaf function has beta1 = 0', () => {
    const func = mockFunction('getConfig', 0, 2);
    const metrics = extractFunctionMetrics(func as never, 'src/config.ts');

    expect(metrics.beta1).toBe(0);
    expect(metrics.isLearning).toBe(false);
    // godWeight = R - min(v, R) + 1 = 2 - min(2, 2) + 1 = 1
    expect(metrics.godWeight).toBe(1);
  });

  test('sovereign function has highest godWeight', () => {
    const func = mockFunction('sovereign', 5, 0);
    const metrics = extractFunctionMetrics(func as never, 'src/core.ts');

    // godWeight = R - min(v, R) + 1 = 5 - 0 + 1 = 6
    expect(metrics.godWeight).toBe(6);
    expect(metrics.isLearning).toBe(true);
  });
});

describe('aggregateFindings', () => {
  test('aggregates metrics across files', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('fn1', 3, 1),
        mockFunction('fn2', 0, 2),
      ]),
      mockFileResult('src/b.ts', [
        mockFunction('fn3', 5, 0),
      ]),
    ];

    const scan = aggregateFindings('test-project', files as never);

    expect(scan.projectName).toBe('test-project');
    expect(scan.functionCount).toBe(3);
    expect(scan.totalBeta1).toBe(8);  // 3 + 0 + 5
    expect(scan.totalDeficit).toBe(3); // 1 + 2 + 0
    expect(scan.filesAnalyzed).toBe(2);
  });

  test('empty project has zero metrics', () => {
    const scan = aggregateFindings('empty', []);

    expect(scan.functionCount).toBe(0);
    expect(scan.totalBeta1).toBe(0);
    expect(scan.totalDeficit).toBe(0);
  });
});

describe('scanToCheckpointedSystem', () => {
  test('maps learning/deaf functions to active/destroyed channels', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('learner1', 3, 0),
        mockFunction('learner2', 1, 0),
        mockFunction('deaf1', 0, 2),
      ]),
    ];

    const scan = aggregateFindings('test', files as never);
    const system = scanToCheckpointedSystem(scan);

    expect(system.active).toBe(2);    // 2 learning functions
    expect(system.destroyed).toBe(1); // 1 deaf function
    expect(system.beta1).toBe(2);
    expect(system.deficit).toBe(1);
    expect(system.isDeaf).toBe(false);
    expect(system.isLearning).toBe(true);
  });

  test('all deaf = necrotic system', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('dead1', 0, 1),
        mockFunction('dead2', 0, 3),
      ]),
    ];

    const scan = aggregateFindings('dead', files as never);
    const system = scanToCheckpointedSystem(scan);

    expect(system.active).toBe(0);
    expect(system.destroyed).toBe(2);
    expect(system.isDeaf).toBe(true);
    expect(system.sicknessFraction).toBe(1);
  });

  test('conservation: active + destroyed = functionCount', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 5, 0),
        mockFunction('f2', 0, 3),
        mockFunction('f3', 1, 1),
        mockFunction('f4', 0, 0),
      ]),
    ];

    const scan = aggregateFindings('test', files as never);
    const system = scanToCheckpointedSystem(scan);

    // f1: beta1=5 (learning), f2: beta1=0 (deaf), f3: beta1=1 (learning), f4: beta1=0 (deaf)
    expect(system.active + system.destroyed).toBe(scan.functionCount);
    expect(system.active).toBe(2);
    expect(system.destroyed).toBe(2);
  });
});

describe('computeRepairOrdering', () => {
  test('sorts by godWeight descending', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('low', 1, 0),     // godWeight = 1 - 0 + 1 = 2
        mockFunction('high', 10, 2),   // godWeight = 12 - 2 + 1 = 11
        mockFunction('mid', 3, 1),     // godWeight = 4 - 1 + 1 = 4
      ]),
    ];

    const scan = aggregateFindings('test', files as never);
    const ordering = computeRepairOrdering(scan);

    expect(ordering[0].functionName).toBe('high');
    expect(ordering[1].functionName).toBe('mid');
    expect(ordering[2].functionName).toBe('low');
  });

  test('respects limit', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 1, 0),
        mockFunction('f2', 2, 0),
        mockFunction('f3', 3, 0),
        mockFunction('f4', 4, 0),
      ]),
    ];

    const scan = aggregateFindings('test', files as never);
    const ordering = computeRepairOrdering(scan, 2);

    expect(ordering.length).toBe(2);
  });
});

describe('diagnoseProject', () => {
  test('healthy project: most functions are learning', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 5, 0),
        mockFunction('f2', 3, 1),
        mockFunction('f3', 2, 0),
        mockFunction('f4', 1, 0),
        mockFunction('f5', 4, 0),
        mockFunction('f6', 2, 0),
        mockFunction('f7', 3, 0),
        mockFunction('f8', 1, 0),
        mockFunction('f9', 2, 0),
        mockFunction('f10', 1, 0),
      ]),
    ];

    const profile = diagnoseProject('healthy', files as never);

    expect(profile.sigma).toBe(0); // all functions have beta1 > 0
    expect(profile.diagnosis.health).toBe('healthy');
    expect(profile.diagnosis.repairPath).toBe('monitoring');
    expect(profile.activeChannels).toBe(10);
    expect(profile.destroyedChannels).toBe(0);
  });

  test('stressed project: some deaf functions', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 3, 0),
        mockFunction('f2', 2, 0),
        mockFunction('f3', 1, 0),
        mockFunction('f4', 0, 1),  // deaf
        mockFunction('f5', 0, 2),  // deaf
      ]),
    ];

    const profile = diagnoseProject('stressed', files as never);

    expect(profile.activeChannels).toBe(3);
    expect(profile.destroyedChannels).toBe(2);
    // sicknessFraction = 2/5 = 0.4
    expect(profile.sigma).toBeCloseTo(0.4);
    expect(profile.diagnosis.health).toBe('inflamed');
    expect(profile.diagnosis.repairPath).toBe('integration');
  });

  test('necrotic project: all deaf', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 0, 1),
        mockFunction('f2', 0, 2),
      ]),
    ];

    const profile = diagnoseProject('dead', files as never);

    expect(profile.sigma).toBe(1);
    expect(profile.diagnosis.health).toBe('necrotic');
    expect(profile.diagnosis.repairPath).toBe('exorcism');
    expect(profile.system.isDeaf).toBe(true);
  });

  test('forecasts are consistent', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 3, 0),
        mockFunction('f2', 0, 1),
        mockFunction('f3', 0, 2),
      ]),
    ];

    const profile = diagnoseProject('test', files as never);

    // After repairing 1 channel: active 2, destroyed 1 → sickness = 1/3
    expect(profile.forecastIfRepaired.active).toBe(2);
    expect(profile.forecastIfRepaired.destroyed).toBe(1);

    // After losing 1 channel: active 0, destroyed 3 → necrotic
    expect(profile.forecastIfNeglected.active).toBe(0);
    expect(profile.forecastIfNeglected.destroyed).toBe(3);
    expect(profile.forecastIfNeglected.isDeaf).toBe(true);
  });
});

describe('diagnoseFromCounts', () => {
  test('quick diagnosis matches full pipeline for same counts', () => {
    const quick = diagnoseFromCounts('test', 7, 3);

    expect(quick.activeChannels).toBe(7);
    expect(quick.destroyedChannels).toBe(3);
    expect(quick.sigma).toBeCloseTo(0.3);
    expect(quick.diagnosis.health).toBe('inflamed');
  });

  test('all active = healthy', () => {
    const quick = diagnoseFromCounts('healthy', 10, 0);

    expect(quick.sigma).toBe(0);
    expect(quick.diagnosis.health).toBe('healthy');
  });

  test('all destroyed = necrotic', () => {
    const quick = diagnoseFromCounts('dead', 0, 5);

    expect(quick.sigma).toBe(1);
    expect(quick.diagnosis.health).toBe('necrotic');
    expect(quick.system.isDeaf).toBe(true);
  });
});

// ── Step 5: Void Dimension Profiles ─────────────────────────────────

describe('directSum', () => {
  test('rank1 and rank0 are additive', () => {
    const a: TwoTermComplex = { rank1: 3, rank0: 2 };
    const b: TwoTermComplex = { rank1: 5, rank0: 1 };
    const sum = directSum(a, b);

    expect(sum.rank1).toBe(8);
    expect(sum.rank0).toBe(3);
  });

  test('direct sum with zero complex is identity', () => {
    const a: TwoTermComplex = { rank1: 7, rank0: 4 };
    const zero: TwoTermComplex = { rank1: 0, rank0: 0 };
    const sum = directSum(a, zero);

    expect(sum.rank1).toBe(a.rank1);
    expect(sum.rank0).toBe(a.rank0);
  });
});

describe('computeVoidProfile', () => {
  test('produces three independent complexes and their direct sum', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 3, 0),
        mockFunction('f2', 2, 1),
      ]),
    ];

    const scan = aggregateFindings('test', files as never);
    const profile = computeVoidProfile(scan, 5, 3, 2);

    // Each dimension should have a TwoTermComplex
    expect(profile.cross_file.rank1).toBeGreaterThanOrEqual(0);
    expect(profile.temporal.rank1).toBeGreaterThanOrEqual(0);
    expect(profile.data_plane.rank1).toBeGreaterThanOrEqual(0);

    // Composite = direct sum of all three
    expect(profile.composite.rank1).toBe(
      profile.cross_file.rank1 + profile.temporal.rank1 + profile.data_plane.rank1
    );
    expect(profile.composite.rank0).toBe(
      profile.cross_file.rank0 + profile.temporal.rank0 + profile.data_plane.rank0
    );

    // Three assessments (one per dimension)
    expect(profile.assessments.length).toBe(3);
    expect(profile.assessments[0].dimension).toBe('cross_file');
    expect(profile.assessments[1].dimension).toBe('temporal');
    expect(profile.assessments[2].dimension).toBe('data_plane');
  });

  test('zero void dimensions produces minimal complexes', () => {
    const scan = aggregateFindings('empty', []);
    const profile = computeVoidProfile(scan);

    // With zero visible crossings, each dimension has 0 visible + >= 1 invisible
    expect(profile.cross_file.rank1).toBe(0);
    expect(profile.temporal.rank1).toBe(0);
    expect(profile.data_plane.rank1).toBe(0);

    // Invisible crossings are at least 1 (lower bound from assessVoidDimension)
    expect(profile.cross_file.rank0).toBeGreaterThanOrEqual(1);
    expect(profile.temporal.rank0).toBeGreaterThanOrEqual(1);
    expect(profile.data_plane.rank0).toBeGreaterThanOrEqual(1);
  });
});

// ── Step 6: Brunnian Coupling ───────────────────────────────────────

describe('computeBrunnianInterference', () => {
  test('returns empty interference when no modules provided', () => {
    const scan = aggregateFindings('test', []);
    const interference = computeBrunnianInterference(scan);

    expect(interference.couplings.length).toBe(0);
    expect(interference.totalEmergentStrength).toBe(0);
    expect(interference.brunnianCount).toBe(0);
    expect(interference.affectedModules.length).toBe(0);
    expect(interference.interferencePenalty).toBe(0);
  });

  test('returns empty interference when fewer than 3 modules', () => {
    const scan = aggregateFindings('test', []);
    const modules = [
      { id: 'a', source: '(a:State)\n(b:State)\n(a)-[:FORK]->(b)' },
      { id: 'b', source: '(c:State)\n(d:State)\n(c)-[:FOLD]->(d)' },
    ];
    const interference = computeBrunnianInterference(scan, modules);

    expect(interference.brunnianCount).toBe(0);
  });
});

// ── Integration: diagnoseProject includes void + brunnian ───────────

describe('diagnoseProject with void + brunnian', () => {
  test('profile includes void dimension profile', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 3, 0),
      ]),
    ];

    const profile = diagnoseProject('test', files as never);

    expect(profile.voidProfile).toBeDefined();
    expect(profile.voidProfile.cross_file).toBeDefined();
    expect(profile.voidProfile.temporal).toBeDefined();
    expect(profile.voidProfile.data_plane).toBeDefined();
    expect(profile.voidProfile.composite).toBeDefined();
  });

  test('profile includes brunnian interference', () => {
    const files = [
      mockFileResult('src/a.ts', [
        mockFunction('f1', 3, 0),
      ]),
    ];

    const profile = diagnoseProject('test', files as never);

    expect(profile.brunnianInterference).toBeDefined();
    expect(profile.brunnianInterference.couplings).toEqual([]);
    expect(profile.brunnianInterference.interferencePenalty).toBe(0);
  });
});
